#!/bin/zsh
# Download all 45 Stitch screen screenshots
set -e
BASE_DIR="$(dirname "$0")"
SS_DIR="$BASE_DIR/screenshots"
mkdir -p "$SS_DIR"

download() {
  local slug="$1" url="$2"
  local out="$SS_DIR/${slug}.png"
  if [ -f "$out" ]; then
    echo "EXISTS: $slug"
    return
  fi
  echo "Downloading: $slug"
  curl -sL -o "$out" "$url" || echo "  FAILED: $slug"
}

